// Hash function for prime products with linear probing
pub fn hashPrimeProduct(prime_product: u64, seed: u64, table_size: u32) u32 {
    var h = prime_product;
    h ^= seed;
    h ^= h >> 33;
    h *%= 0xff51afd7ed558ccd;
    h ^= h >> 33;
    h *%= 0xc4ceb9fe1a85ec53;
    h ^= h >> 33;
    h *%= 0x9e3779b97f4a7c15;
    h ^= h >> 29;
    return @intCast(h & (table_size - 1));
}

// Lookup with linear probing for collision resolution
pub fn lookupPairedHand(prime_product: u64) u32 {
    const hash_index = hashPrimeProduct(prime_product, PAIR_HASH_SEED, PAIR_LOOKUP_SIZE);

    // Direct lookup - simplified for now
    return if (PAIR_LOOKUP[hash_index] != 0) PAIR_LOOKUP[hash_index] else 1; // fallback to high_card
}
